// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RepositoryMovement) predicate.RepositoryMovement {
	return predicate.RepositoryMovement(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RepositoryMovement) predicate.RepositoryMovement {
	return predicate.RepositoryMovement(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RepositoryMovement) predicate.RepositoryMovement {
	return predicate.RepositoryMovement(sql.NotPredicates(p))
}
